var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"지식<color=#ff3636>의 성찬</color>이 준비되었<color=#ff3636>다. </color>","JPN":"知識<color=#ff3636>の聖餐</color>の準備が整っ<color=#ff3636>た。</color>","ENG":"The fe<color=#ff3636>ast of know</color>ledge has be<color=#ff3636>en prepared. </color>","TWN":"知識<color=#ff3636>的饗宴</color>準備<color=#ff3636>好了。 </color>"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OCTOPUS3_ESPR_NULL_NULL","text":{"KOREA":"<color=#ff3636>연회는</color> 아직<b>인</b>가.","JPN":"<color=#ff3636>宴会は</color>まだ<b>なの</b>か。","ENG":"Wh<color=#ff3636>en shall th</color>e ba<b>nquet b</b>egin?","TWN":"<color=#ff3636>宴會</color>還沒<b>開始</b>嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"가, 가까이 오지 마! 가까이 오지 마!!","JPN":"く、来るな！　来るな！！","ENG":"G-get away from me! Get away from me!","TWN":"別…別過來！走開！！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"이것들은 뭐야…… 이 괴물들은 다 뭐냐고……!","JPN":"こいつらはなんだ……この化け物たちは何なんだよ！","ENG":"What's all this…? What are these monsters doing here?!","TWN":"這些東西是怎樣……這些怪物到底都是些什麼……！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"흐음. 이 얼간이에게서 얻을 지식은 이걸로 끝인 것 같군.","JPN":"ふーん、この間抜けから得られる知識はこれで終わりのようだな。","ENG":"Hmm... Hmm. It seems this is all the knowledge the fool has to offer.","TWN":"嗯，似乎無法再從這傻瓜身上取得任何知識了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"어서 제물을 바칠 의식을 준비해. <color=#ffd34c>호수</color>가 굶주려하는 간격이 더 짧아지고 있어.","JPN":"早く生贄を捧げる儀式の準備をしなさい。<color=#ffd34c>湖</color>が飢える間隔が短くなっているの。","ENG":"Prepare the sacrifice ritual with haste. The intervals between the <color=#ffd34c>Lake</color>'s hunger pangs keep growing shorter.","TWN":"快準備獻祭儀式吧。<color=#ffd34c>湖水</color>飢餓的週期越來越短了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"그리고 다음부터는 더 요긴한 지식을 지닌 놈으로 선발하면 좋겠군.","JPN":"あと、次からはもう少し使える知識を持っている奴にしてちょうだい。","ENG":"And next time, I wish you'd bring someone with more useful knowledge.","TWN":"另外，我希望之後挑的人可以具備更重要的知識。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"살려 주세요! 살려만 주시면 뭐든 하겠습니다! 뭐든지요!","JPN":"助けてください！　助けてくだされば何でもやります！　なんでも！","ENG":"Please don't kill me! I'll do anything if you spare me! Anything!","TWN":"放過我吧！只要不殺我，我什麼都願意做，任何事！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_NULL","text":{"KOREA":"막노동할 사람은 안 필요하십니까? 쓰레기를 치울 사람은요! 뭐든지 제발 시켜 주세요!","JPN":"現場の作業員は必要ありませんか？　ゴミを片付ける人は？　お願いですから何でもやらせてください！","ENG":"Do you need anyone to do your chores? How about a janitor? Please, I'll do anything!","TWN":"需要壯丁嗎？還是幫你倒垃圾？拜託派事情給我做！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장님. 실례지만 저 원숭이를 제물로 바치는 건 재고해 주시죠.","JPN":"学会長。失礼ですが、あの猿を生贄に捧げることは再考してください。","ENG":"Ms. President. If I may, please reconsider offering that animal as a sacrifice.","TWN":"會長，請恕我直言，用猴子獻祭一事還請三思。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"왜, 저런 무지한 것에게 미련이라도 남았나?","JPN":"なに、あの無知な者に未練でも残っているのか？","ENG":"Why? Are you somehow attached to that ignoramus?","TWN":"為何？你捨不得這個無知的東西嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맑은 호수에 오물을 버리는 몰상식한 행위와 다를 바 없기 때문이죠.","JPN":"清らかな湖に汚物を捨てる常識外れの行為と変わらないからです。","ENG":"It's only because this would be akin to adulterating a pristine lake with excrement.","TWN":"因為這無疑是把污染物扔進清澈湖水的無知行為。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"지금 같은 시기에 호수의 제물로 바쳐진다는 것은 저 원숭이에게 과분한 영광입니다.","JPN":"今のような時期に湖の生贄として捧げられるということは、あの猿にとって過分な光栄です。","ENG":"Becoming a sacrifice unto the Lake at a time like this is an honor far beyond what that animal deserves.","TWN":"就此刻而言，那隻猴子不配當作祭物獻給湖水。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"기관의 방해로 오래토록 이어진 허기를 달랠 제물이니, 더욱 엄선해야 하지 않겠습니까?","JPN":"機関の妨害で長く続いた空腹を満たすための生贄ですから、もっと厳選すべきではないでしょうか？","ENG":"The next sacrifice must satiate the prolonged hunger wrought by the Institution's interference. Surely we must curate a more worthy repast?","TWN":"因為這個祭物是要解決，因機關的阻礙而長久累積的飢餓，難道不該慎選嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"……그렇다면 나는 그 역겨운 버넷밖에 생각나지 않아.","JPN":"……それなら、代わりはあの鬱陶しいバーネットしか思い浮かばないのだが。","ENG":"…That only reminds me of that disgusting wretch, Burnett.","TWN":"……那我腦中想到的人選，就只有那個討厭的伯內特。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"버넷 경과 사적으로 몇 차례 불미스러운 사건이 있으셨다는 사실은 저도 잘 알고 있습니다.","JPN":"バーネット卿とはプライベートで何度か不祥事があったことは承知しています。","ENG":"I'm well aware that you've had several undesirable personal exchanges with Sir Burnett.","TWN":"我也知道會長和伯內特卿有些私人恩怨。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그의 사슬이 호수와 상극이라는 것 역시 말이죠.","JPN":"彼の鎖が湖と相克ということもです。","ENG":"And also that his chain is most formidably incompatible with the Lake.","TWN":"而且他的鐵鍊和湖水相剋也是事實。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OCTOPUS2_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};